import { jest } from '@jest/globals';
import CommandHandler from '../src/cli/CommandHandler.js';

// Mock dependencies
const mockConfigManager = {
  displayConfig: jest.fn(),
  runSetupWizard: jest.fn(),
  updateConfig: jest.fn()
};

const mockContextManager = {
  clear: jest.fn(),
  getStats: jest.fn(() => ({
    messageCount: 5,
    totalTokens: 1000,
    maxTokens: 4000,
    tokenUsagePercent: 25,
    fileCount: 3,
    isNearLimit: false
  })),
  getAllFileContexts: jest.fn(() => [
    {
      path: 'src/test.js',
      language: 'javascript',
      size: 1024,
      addedAt: new Date('2023-01-01')
    },
    {
      path: 'README.md',
      language: 'markdown',
      size: 512,
      addedAt: new Date('2023-01-02')
    }
  ])
};

const mockSearchEngine = {
  search: jest.fn(),
  rankResults: jest.fn((results) => results)
};

const mockToolRegistry = {
  getToolNames: jest.fn(() => ['read_file', 'write_file', 'execute_command']),
  getToolByName: jest.fn((name) => ({
    schema: {
      name,
      description: `Mock description for ${name}`,
      parameters: {
        properties: {
          path: { type: 'string', description: 'File path' },
          content: { type: 'string', description: 'File content' }
        },
        required: ['path']
      }
    }
  }))
};

const mockApprovalManager = {
  getAutonomyMode: jest.fn(() => 'safe'),
  setAutonomyMode: jest.fn(),
  isAutoApproved: jest.fn(() => false)
};

const mockTerminalInterface = {
  displayError: jest.fn(),
  displayInfo: jest.fn(),
  displaySuccess: jest.fn(),
  displayWarning: jest.fn(),
  displayWelcome: jest.fn()
};

describe('CommandHandler', () => {
  let commandHandler;

  beforeEach(() => {
    // Reset all mocks
    jest.clearAllMocks();
    
    commandHandler = new CommandHandler(
      mockConfigManager,
      mockContextManager,
      mockSearchEngine,
      mockToolRegistry,
      mockApprovalManager,
      mockTerminalInterface
    );
  });

  describe('constructor', () => {
    it('should create CommandHandler with all dependencies', () => {
      expect(commandHandler).toBeInstanceOf(CommandHandler);
      expect(commandHandler.configManager).toBe(mockConfigManager);
      expect(commandHandler.contextManager).toBe(mockContextManager);
      expect(commandHandler.searchEngine).toBe(mockSearchEngine);
      expect(commandHandler.toolRegistry).toBe(mockToolRegistry);
      expect(commandHandler.approvalManager).toBe(mockApprovalManager);
      expect(commandHandler.terminal).toBe(mockTerminalInterface);
    });

    it('should throw error if ConfigManager is missing', () => {
      expect(() => {
        new CommandHandler(null, mockContextManager, mockSearchEngine, mockToolRegistry, mockApprovalManager, mockTerminalInterface);
      }).toThrow('ConfigManager is required');
    });

    it('should throw error if ContextManager is missing', () => {
      expect(() => {
        new CommandHandler(mockConfigManager, null, mockSearchEngine, mockToolRegistry, mockApprovalManager, mockTerminalInterface);
      }).toThrow('ContextManager is required');
    });

    it('should throw error if SearchEngine is missing', () => {
      expect(() => {
        new CommandHandler(mockConfigManager, mockContextManager, null, mockToolRegistry, mockApprovalManager, mockTerminalInterface);
      }).toThrow('SearchEngine is required');
    });

    it('should throw error if ToolRegistry is missing', () => {
      expect(() => {
        new CommandHandler(mockConfigManager, mockContextManager, mockSearchEngine, null, mockApprovalManager, mockTerminalInterface);
      }).toThrow('ToolRegistry is required');
    });

    it('should throw error if ApprovalManager is missing', () => {
      expect(() => {
        new CommandHandler(mockConfigManager, mockContextManager, mockSearchEngine, mockToolRegistry, null, mockTerminalInterface);
      }).toThrow('ApprovalManager is required');
    });

    it('should throw error if TerminalInterface is missing', () => {
      expect(() => {
        new CommandHandler(mockConfigManager, mockContextManager, mockSearchEngine, mockToolRegistry, mockApprovalManager, null);
      }).toThrow('TerminalInterface is required');
    });
  });

  describe('isCommand', () => {
    it('should return true for messages starting with /', () => {
      expect(commandHandler.isCommand('/help')).toBe(true);
      expect(commandHandler.isCommand('/clear')).toBe(true);
      expect(commandHandler.isCommand('  /search test')).toBe(true);
    });

    it('should return false for regular messages', () => {
      expect(commandHandler.isCommand('hello')).toBe(false);
      expect(commandHandler.isCommand('help')).toBe(false);
      expect(commandHandler.isCommand('')).toBe(false);
      expect(commandHandler.isCommand(null)).toBe(false);
      expect(commandHandler.isCommand(undefined)).toBe(false);
    });
  });

  describe('executeCommand', () => {
    it('should return false for non-commands', async () => {
      const result = await commandHandler.executeCommand('hello');
      expect(result).toBe(false);
    });

    it('should handle unknown commands', async () => {
      const result = await commandHandler.executeCommand('/unknown');
      expect(result).toBe(true);
      expect(mockTerminalInterface.displayError).toHaveBeenCalledWith('Unknown command: /unknown');
      expect(mockTerminalInterface.displayInfo).toHaveBeenCalledWith('Type /help to see available commands');
    });

    it('should execute known commands', async () => {
      const result = await commandHandler.executeCommand('/clear');
      expect(result).toBe(true);
      expect(mockContextManager.clear).toHaveBeenCalled();
    });

    it('should handle command execution errors', async () => {
      mockContextManager.clear.mockImplementation(() => {
        throw new Error('Test error');
      });

      const result = await commandHandler.executeCommand('/clear');
      expect(result).toBe(true);
      expect(mockTerminalInterface.displayError).toHaveBeenCalledWith('Command failed: Test error');
    });
  });

  describe('handleHelp', () => {
    it('should show general help when no arguments provided', async () => {
      const consoleSpy = jest.spyOn(console, 'log').mockImplementation(() => {});
      
      await commandHandler.handleHelp([]);
      
      expect(consoleSpy).toHaveBeenCalled();
      consoleSpy.mockRestore();
    });

    it('should show specific command help when command provided', async () => {
      const consoleSpy = jest.spyOn(console, 'log').mockImplementation(() => {});
      
      await commandHandler.handleHelp(['search']);
      
      expect(consoleSpy).toHaveBeenCalled();
      consoleSpy.mockRestore();
    });
  });

  describe('handleClear', () => {
    it('should clear context and display success message', async () => {
      // Reset the mock to ensure it doesn't throw
      mockContextManager.clear.mockImplementation(() => {});
      
      await commandHandler.handleClear([]);
      
      expect(mockContextManager.clear).toHaveBeenCalled();
      expect(mockTerminalInterface.displaySuccess).toHaveBeenCalledWith('Context cleared successfully');
      expect(mockTerminalInterface.displayInfo).toHaveBeenCalledWith('Cleared 5 messages and 3 file contexts');
    });
  });

  describe('handleSearch', () => {
    it('should display error when no query provided', async () => {
      await commandHandler.handleSearch([]);
      
      expect(mockTerminalInterface.displayError).toHaveBeenCalledWith('Usage: /search <query> [options]');
    });

    it('should perform search with query', async () => {
      const mockResults = [
        {
          filePath: 'src/test.js',
          lineNumber: 10,
          line: 'function test() {',
          context: { before: [], after: [] },
          language: 'javascript'
        }
      ];
      
      mockSearchEngine.search.mockResolvedValue(mockResults);
      const consoleSpy = jest.spyOn(console, 'log').mockImplementation(() => {});
      
      await commandHandler.handleSearch(['test']);
      
      expect(mockSearchEngine.search).toHaveBeenCalledWith('test', {
        caseSensitive: false,
        wholeWord: false,
        contextLines: 2
      });
      expect(mockTerminalInterface.displaySuccess).toHaveBeenCalledWith('Found 1 results (showing top 1):');
      
      consoleSpy.mockRestore();
    });

    it('should handle search options', async () => {
      mockSearchEngine.search.mockResolvedValue([]);
      
      await commandHandler.handleSearch(['test', '--case-sensitive', '--whole-word', '--context=5']);
      
      expect(mockSearchEngine.search).toHaveBeenCalledWith('test', {
        caseSensitive: true,
        wholeWord: true,
        contextLines: 5
      });
    });

    it('should handle search errors', async () => {
      mockSearchEngine.search.mockRejectedValue(new Error('Search failed'));
      
      await commandHandler.handleSearch(['test']);
      
      expect(mockTerminalInterface.displayError).toHaveBeenCalledWith('Search failed: Search failed');
    });

    it('should display warning when no results found', async () => {
      mockSearchEngine.search.mockResolvedValue([]);
      
      await commandHandler.handleSearch(['test']);
      
      expect(mockTerminalInterface.displayWarning).toHaveBeenCalledWith('No results found');
    });
  });

  describe('handleFiles', () => {
    it('should display files in context', async () => {
      const consoleSpy = jest.spyOn(console, 'log').mockImplementation(() => {});
      
      await commandHandler.handleFiles([]);
      
      expect(mockContextManager.getAllFileContexts).toHaveBeenCalled();
      expect(mockTerminalInterface.displaySuccess).toHaveBeenCalledWith('Files in context (2):');
      
      consoleSpy.mockRestore();
    });

    it('should display message when no files in context', async () => {
      mockContextManager.getAllFileContexts.mockReturnValue([]);
      
      await commandHandler.handleFiles([]);
      
      expect(mockTerminalInterface.displayInfo).toHaveBeenCalledWith('No files currently in context');
    });
  });

  describe('handleConfig', () => {
    it('should display configuration', async () => {
      await commandHandler.handleConfig([]);
      
      expect(mockConfigManager.displayConfig).toHaveBeenCalled();
    });
  });

  describe('handleSetup', () => {
    it('should run setup wizard successfully', async () => {
      const mockConfig = { agent: { autonomyMode: 'autonomous' } };
      mockConfigManager.runSetupWizard.mockResolvedValue(mockConfig);
      
      await commandHandler.handleSetup([]);
      
      expect(mockTerminalInterface.displayInfo).toHaveBeenCalledWith('Starting configuration wizard...');
      expect(mockConfigManager.runSetupWizard).toHaveBeenCalled();
      expect(mockTerminalInterface.displaySuccess).toHaveBeenCalledWith('Configuration wizard completed successfully!');
      expect(mockApprovalManager.setAutonomyMode).toHaveBeenCalledWith('autonomous');
    });

    it('should handle setup cancellation', async () => {
      mockConfigManager.runSetupWizard.mockRejectedValue(new Error('Setup cancelled by user'));
      
      await commandHandler.handleSetup([]);
      
      expect(mockTerminalInterface.displayWarning).toHaveBeenCalledWith('Configuration wizard cancelled');
    });

    it('should handle setup errors', async () => {
      mockConfigManager.runSetupWizard.mockRejectedValue(new Error('Setup failed'));
      
      await commandHandler.handleSetup([]);
      
      expect(mockTerminalInterface.displayError).toHaveBeenCalledWith('Setup failed: Setup failed');
    });
  });

  describe('handleSet', () => {
    it('should display usage when insufficient arguments', async () => {
      await commandHandler.handleSet(['key']);
      
      expect(mockTerminalInterface.displayError).toHaveBeenCalledWith('Usage: /set <key> <value>');
    });

    it('should update configuration successfully', async () => {
      await commandHandler.handleSet(['mistral.model', 'mistral-large-latest']);
      
      expect(mockConfigManager.updateConfig).toHaveBeenCalledWith('mistral.model', 'mistral-large-latest');
    });

    it('should handle autonomy mode changes', async () => {
      await commandHandler.handleSet(['agent.autonomyMode', 'autonomous']);
      
      expect(mockConfigManager.updateConfig).toHaveBeenCalledWith('agent.autonomyMode', 'autonomous');
      expect(mockApprovalManager.setAutonomyMode).toHaveBeenCalledWith('autonomous');
    });

    it('should handle configuration update errors', async () => {
      mockConfigManager.updateConfig.mockRejectedValue(new Error('Invalid key'));
      
      await commandHandler.handleSet(['invalid.key', 'value']);
      
      expect(mockTerminalInterface.displayError).toHaveBeenCalledWith('Failed to update configuration: Invalid key');
    });

    it('should join multiple value arguments', async () => {
      await commandHandler.handleSet(['key', 'value', 'with', 'spaces']);
      
      expect(mockConfigManager.updateConfig).toHaveBeenCalledWith('key', 'value with spaces');
    });
  });

  describe('handleMode', () => {
    it('should display current mode when no arguments', async () => {
      const consoleSpy = jest.spyOn(console, 'log').mockImplementation(() => {});
      
      await commandHandler.handleMode([]);
      
      expect(mockApprovalManager.getAutonomyMode).toHaveBeenCalled();
      expect(consoleSpy).toHaveBeenCalled();
      
      consoleSpy.mockRestore();
    });

    it('should change autonomy mode', async () => {
      await commandHandler.handleMode(['autonomous']);
      
      expect(mockApprovalManager.setAutonomyMode).toHaveBeenCalledWith('autonomous');
      expect(mockConfigManager.updateConfig).toHaveBeenCalledWith('agent.autonomyMode', 'autonomous');
    });

    it('should handle mode change errors', async () => {
      mockApprovalManager.setAutonomyMode.mockImplementation(() => {
        throw new Error('Invalid mode');
      });
      
      await commandHandler.handleMode(['invalid']);
      
      expect(mockTerminalInterface.displayError).toHaveBeenCalledWith('Failed to change mode: Invalid mode');
    });
  });

  describe('handleTools', () => {
    it('should display all tools when no arguments', async () => {
      const consoleSpy = jest.spyOn(console, 'log').mockImplementation(() => {});
      
      await commandHandler.handleTools([]);
      
      expect(mockToolRegistry.getToolNames).toHaveBeenCalled();
      expect(consoleSpy).toHaveBeenCalled();
      
      consoleSpy.mockRestore();
    });

    it('should display specific tool details', async () => {
      const consoleSpy = jest.spyOn(console, 'log').mockImplementation(() => {});
      
      await commandHandler.handleTools(['read_file']);
      
      expect(mockToolRegistry.getToolByName).toHaveBeenCalledWith('read_file');
      expect(consoleSpy).toHaveBeenCalled();
      
      consoleSpy.mockRestore();
    });

    it('should handle unknown tool', async () => {
      mockToolRegistry.getToolByName.mockReturnValue(null);
      
      await commandHandler.handleTools(['unknown_tool']);
      
      expect(mockTerminalInterface.displayError).toHaveBeenCalledWith('Tool not found: unknown_tool');
    });

    it('should display warning when no tools registered', async () => {
      mockToolRegistry.getToolNames.mockReturnValue([]);
      
      await commandHandler.handleTools([]);
      
      expect(mockTerminalInterface.displayWarning).toHaveBeenCalledWith('No tools are currently registered');
    });
  });

  describe('startTerminal', () => {
    it('should display welcome message and help info', () => {
      commandHandler.startTerminal();
      
      expect(mockTerminalInterface.displayWelcome).toHaveBeenCalled();
      expect(mockTerminalInterface.displayInfo).toHaveBeenCalledWith('Type /help for available commands');
    });
  });
});